/** Strip markdown heading markers and collapse to plain text for card preview */ function cleanDescription(raw) {
    return raw.replace(/^#{1,6}\s+.*$/gm, "") // strip all heading lines
    .replace(/\*\*([^*]+)\*\*/g, "$1") // strip bold markers
    .replace(/`([^`]+)`/g, "$1") // strip inline code
    .replace(/\n{2,}/g, " ") // collapse paragraph breaks
    .replace(/\n/g, " ") // collapse remaining newlines
    .replace(/\s{2,}/g, " ") // collapse whitespace
    .trim();
}
